def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 3:
            value = ratio ** 4
            penalty = 0
            for k in range(1, 6):
                penalty += (ratio ** (2 * k + 1)) / (k + 1)**3
            priorities[i] = value + penalty
        elif 1 < ratio <= 3:
            total_penalty = 0
            for x in range(1, 4):
                for y in range(1, 4):
                    term = ((-1) ** (x + y)) * (ratio ** (x + y)) / (x * y)
                    total_penalty += term
            priorities[i] = ratio ** 3 + abs(total_penalty) * 7
            if ratio > 2.5:
                extra = 0
                for m in range(1, 5):
                    extra += (ratio ** m) / (2 * m + 1)
                priorities[i] += extra * 2
        elif 0 < ratio <= 1:
            cumulative = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1
                term = sign * (ratio ** j) / (j ** 2)
                cumulative += term
            base_score = abs(cumulative) * (20 if ratio < 0.2 else 12 if ratio < 0.5 else 6)
            bonus = 0
            if ratio > 0.7:
                for n in range(1, 5):
                    bonus += ((-1) ** n) * (ratio ** (2 * n)) / (n + 1)
            priorities[i] = base_score + bonus
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf:
            decay = 0
            for p in range(1, 4):
                decay += np.exp(-p * ratio) / p
            priorities[i] *= (1 + decay)
    return priorities
